queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type ?cost WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasProjects ?child ; p:hasPreservation_Societies ?parent . } GROUP BY ?child }
  ?child p:Type ?type .
  ?child p:Cost ?cost .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Preservation_Societies } }
  FILTER(?nf = ?total)
}

